-- Seed four more generic DSL templates: Beginner Upper/Lower, Ramping 5x5,
-- Power + Hypertrophy U/L, and 3-Day Strength (Volume to Intensity).
-- Generated from the in-code fallbackTemplateDefinitions so the DB definition never
-- drifts from the TypeScript source (see tests/_generate-seed.test.ts).

insert into public.program_templates (
  id, name, source, description, days_per_week, progression_label, complexity, schema_version, tags
) values
  ('beginner_upper_lower_lp', 'Beginner Upper/Lower', 'linear_strength', 'Four-day upper/lower split for beginners — straight-set linear progression on the main lifts with simple accessories.', 4, 'Working-load LP', 'Beginner', '2026.06.dsl', array['linear', 'beginner', 'upper-lower']::text[]),
  ('ramping_5x5_3day', 'Ramping 5x5', 'linear_strength', 'Three-day intermediate 5x5 with a heavy ramp, a recovery day, and a volume day — loads climb week to week.', 3, 'Weekly working-load LP', 'Intermediate', '2026.06.dsl', array['5x5', 'linear', 'strength']::text[]),
  ('power_hypertrophy_ul', 'Power + Hypertrophy U/L', 'wave_powerbuilding', 'Four-day powerbuilding split — two heavy power days plus two higher-rep hypertrophy days for size and strength.', 4, 'Power LP + hypertrophy', 'Intermediate', '2026.06.dsl', array['powerbuilding', 'volume', 'hypertrophy', 'upper-lower']::text[]),
  ('weekly_intensity_3day', '3-Day Strength (Volume to Intensity)', 'volume_strength', 'Advanced three-day plan — a volume day, a recovery day, and a weekly intensity day chasing new top sets.', 3, 'Weekly volume to intensity', 'Advanced', '2026.06.dsl', array['strength', 'intensity', 'peak']::text[])
on conflict (id) do update set
  name = excluded.name,
  source = excluded.source,
  description = excluded.description,
  days_per_week = excluded.days_per_week,
  progression_label = excluded.progression_label,
  complexity = excluded.complexity,
  schema_version = excluded.schema_version,
  tags = excluded.tags,
  is_active = true;

